const e=JSON.parse('{"key":"v-3cde4746","path":"/%E6%95%B0%E6%8D%AE%E5%BA%93/MySQL/%E5%9F%BA%E7%A1%80%E7%AF%87/18-MySQL8%E6%96%B0%E7%89%B9%E6%80%A7.html","title":"MySQL8新特性","lang":"zh-CN","frontmatter":{"date":"2021-09-10T00:00:00.000Z","category":["数据库","MySQL"],"tag":["MySQL"],"order":18,"description":"MySQL8新特性 1. MySQL8新特性概述 MySQL从5.7版本直接跳跃发布了8.0版本 ，可见这是一个令人兴奋的里程碑版本。MySQL 8版本在功能上做了显著的改进与增强，开发者对MySQL的源代码进行了重构，最突出的一点是多MySQL Optimizer优化器进行了改进。不仅在速度上得到了改善，还为用户带来了更好的性能和更棒的体验。 1.1 MySQL8.0 新增特性 更简便的NoSQL支持 NoSQL泛指非关系型数据库和数据存储。随着互联网平台的规模飞速发展，传统的关系型数据库已经越来越不能满足需求。从5.6版本开始，MySQL就开始支持简单的NoSQL存储功能。MySQL 8对这一功能做了优化，以更灵活的方式实现NoSQL功能，不再依赖模式（schema）。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/%E6%95%B0%E6%8D%AE%E5%BA%93/MySQL/%E5%9F%BA%E7%A1%80%E7%AF%87/18-MySQL8%E6%96%B0%E7%89%B9%E6%80%A7.html"}],["meta",{"property":"og:site_name","content":"Journey of Growth"}],["meta",{"property":"og:title","content":"MySQL8新特性"}],["meta",{"property":"og:description","content":"MySQL8新特性 1. MySQL8新特性概述 MySQL从5.7版本直接跳跃发布了8.0版本 ，可见这是一个令人兴奋的里程碑版本。MySQL 8版本在功能上做了显著的改进与增强，开发者对MySQL的源代码进行了重构，最突出的一点是多MySQL Optimizer优化器进行了改进。不仅在速度上得到了改善，还为用户带来了更好的性能和更棒的体验。 1.1 MySQL8.0 新增特性 更简便的NoSQL支持 NoSQL泛指非关系型数据库和数据存储。随着互联网平台的规模飞速发展，传统的关系型数据库已经越来越不能满足需求。从5.6版本开始，MySQL就开始支持简单的NoSQL存储功能。MySQL 8对这一功能做了优化，以更灵活的方式实现NoSQL功能，不再依赖模式（schema）。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-11-30T08:57:22.000Z"}],["meta",{"property":"article:author","content":"Mr.G"}],["meta",{"property":"article:tag","content":"MySQL"}],["meta",{"property":"article:published_time","content":"2021-09-10T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-11-30T08:57:22.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"MySQL8新特性\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2021-09-10T00:00:00.000Z\\",\\"dateModified\\":\\"2023-11-30T08:57:22.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.G\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"1. MySQL8新特性概述","slug":"_1-mysql8新特性概述","link":"#_1-mysql8新特性概述","children":[{"level":3,"title":"1.1 MySQL8.0 新增特性","slug":"_1-1-mysql8-0-新增特性","link":"#_1-1-mysql8-0-新增特性","children":[]},{"level":3,"title":"1.2 MySQL8.0移除的旧特性","slug":"_1-2-mysql8-0移除的旧特性","link":"#_1-2-mysql8-0移除的旧特性","children":[]}]},{"level":2,"title":"2. 新特性1：窗口函数","slug":"_2-新特性1-窗口函数","link":"#_2-新特性1-窗口函数","children":[{"level":3,"title":"2.1 使用窗口函数前后对比","slug":"_2-1-使用窗口函数前后对比","link":"#_2-1-使用窗口函数前后对比","children":[]},{"level":3,"title":"2.2 窗口函数分类","slug":"_2-2-窗口函数分类","link":"#_2-2-窗口函数分类","children":[]},{"level":3,"title":"2.3 语法结构","slug":"_2-3-语法结构","link":"#_2-3-语法结构","children":[]},{"level":3,"title":"2.4 分类讲解","slug":"_2-4-分类讲解","link":"#_2-4-分类讲解","children":[]},{"level":3,"title":"2.5 小 结","slug":"_2-5-小-结","link":"#_2-5-小-结","children":[]}]},{"level":2,"title":"3. 新特性2：公用表表达式","slug":"_3-新特性2-公用表表达式","link":"#_3-新特性2-公用表表达式","children":[{"level":3,"title":"3.1 普通公用表表达式","slug":"_3-1-普通公用表表达式","link":"#_3-1-普通公用表表达式","children":[]},{"level":3,"title":"3.2 递归公用表表达式","slug":"_3-2-递归公用表表达式","link":"#_3-2-递归公用表表达式","children":[]},{"level":3,"title":"3.3 小 结","slug":"_3-3-小-结","link":"#_3-3-小-结","children":[]}]}],"git":{"createdTime":1701334642000,"updatedTime":1701334642000,"contributors":[{"name":"gm-hacker","email":"gm-hacker@qq.com","commits":1}]},"readingTime":{"minutes":31.72,"words":9515},"filePathRelative":"数据库/MySQL/基础篇/18-MySQL8新特性.md","localizedDate":"2021年9月10日","excerpt":"<h1> MySQL8新特性</h1>\\n<h2> 1. MySQL8新特性概述</h2>\\n<p>MySQL从5.7版本直接跳跃发布了8.0版本 ，可见这是一个令人兴奋的里程碑版本。MySQL 8版本在功能上做了显著的改进与增强，开发者对MySQL的源代码进行了重构，最突出的一点是多MySQL Optimizer优化器进行了改进。不仅在速度上得到了改善，还为用户带来了更好的性能和更棒的体验。</p>\\n<h3> 1.1 MySQL8.0 新增特性</h3>\\n<ul>\\n<li>更简便的NoSQL支持</li>\\n</ul>\\n<p>NoSQL泛指非关系型数据库和数据存储。随着互联网平台的规模飞速发展，传统的关系型数据库已经越来越不能满足需求。从5.6版本开始，MySQL就开始支持简单的NoSQL存储功能。MySQL 8对这一功能做了优化，以更灵活的方式实现NoSQL功能，不再依赖模式（schema）。</p>","autoDesc":true}');export{e as data};
